CREATE TABLE "GuildPlaybook" ("id" TEXT NOT NULL, "key" TEXT NOT NULL, "title" TEXT NOT NULL, "contentType" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL, CONSTRAINT "GuildPlaybook_pkey" PRIMARY KEY ("id"));
