CREATE TABLE "GuildPlaybookLesson" ("id" TEXT NOT NULL, "operationId" TEXT NOT NULL, "sourceKey" TEXT NOT NULL, "playbookId" TEXT, "title" TEXT NOT NULL, "lessonPt" TEXT NOT NULL, "lessonEn" TEXT NOT NULL, "disposition" "PlaybookLessonDisposition" NOT NULL, "ownerId" TEXT NOT NULL, "reviewAt" TIMESTAMP(3) NOT NULL, "createdById" TEXT NOT NULL, "promotedVersionId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "GuildPlaybookLesson_pkey" PRIMARY KEY ("id"));
